/**
 * @interface normalizedType
 * @param {boolean} inRange (optional)
 * @param {number} x
 * @param {number} y
 */
export interface normalizedType {
    inRange?: boolean;
    x: number;
    y: number;
}
/**
 * @interface videoResType
 * @param {number} width
 * @param {number} height
 */
export interface videoResType {
    width: number;
    height: number;
}
/**
 * @interface callbackType
 * @param {string} name
 * @param {Function} func ((e: any, opt?: {obj?: callbackType, objs?: Array<callbackType>}) => void)
 */
export interface callbackType {
    name: string;
    func: (e: any, opt?: {
        obj?: callbackType;
        objs?: Array<callbackType>;
    }) => void;
}
